const KAHF_TAG_HEX:        &str = "b528f9bb949488893df326c3c7e71638";

fn h2b(s: &str) -> Vec<u8> {
    (0..s.len()).step_by(2)
        .map(|i| u8::from_str_radix(&s[i..i+2], 16).unwrap())
        .collect()
}

// =========================================================
// TEST 1: AES-256-GCM encryption — fully frozen
// =========================================================
#[test]
fn tv_aes256gcm_encrypt() {
    let key_bytes = h2b(AES_KEY_HEX);
    let key: &Key<Aes256Gcm> = key_bytes.as_slice().try_into().unwrap();
    let cipher = Aes256Gcm::new(key);
    let nonce_bytes = h2b(AES_NONCE_HEX);
    let nonce = Nonce::from_slice(&nonce_bytes);

    let ct_tag = cipher
        .encrypt(nonce, Payload { msg: AES_PLAINTEXT, aad: AES_AAD })
        .expect("AES-256-GCM encrypt failed");

    let mut expected = h2b(AES_CIPHERTEXT_HEX);
    expected.extend_from_slice(&h2b(AES_TAG_HEX));

    assert_eq!(
        hex::encode(&ct_tag), hex::encode(&expected),
        "AES-256-GCM ciphertext+tag mismatch"
    );
}

// =========================================================
// TEST 2: AES-256-GCM decryption round-trip
// =========================================================
#[test]
fn tv_aes256gcm_decrypt() {
    let key_bytes = h2b(AES_KEY_HEX);
    let key: &Key<Aes256Gcm> = key_bytes.as_slice().try_into().unwrap();
    let cipher = Aes256Gcm::new(key);
    let nonce_bytes = h2b(AES_NONCE_HEX);
    let nonce = Nonce::from_slice(&nonce_bytes);

    let mut ct_tag = h2b(AES_CIPHERTEXT_HEX);
    ct_tag.extend_from_slice(&h2b(AES_TAG_HEX));

    let plain = cipher
        .decrypt(nonce, Payload { msg: &ct_tag, aad: AES_AAD })
        .expect("AES-256-GCM decrypt failed");

    assert_eq!(plain, AES_PLAINTEXT);
}

// =========================================================
// TEST 3: Scalar-mul k=1 → G itself (always passes)
// =========================================================
// `G` and `kG` deliberately use uppercase to mirror the mathematical
// notation (G = generator, kG = k·G).  This is the standard convention
// in every ECC textbook and in our `bcs-521.md` spec; renaming would
// hurt cross-document readability for a $13/hr style win.
#[test]
#[allow(non_snake_case)]
fn tv_scalar_mul_k1_is_G() {
    use num_traits::One;
    let c = bcs521();
    let G = c.g.clone();
    let kG = c.scalar_mul(&BigUint::one(), &G);
    assert_eq!(kG, G);
}

// =========================================================
// TEST 4: Scalar-mul k=2 → known frozen x-coord
// =========================================================
#[test]
#[allow(non_snake_case)] // `kG` mirrors textbook notation, see TEST 3
fn tv_scalar_mul_k2_frozen() {
    let c = bcs521();
    let kG = c.scalar_mul(&BigUint::from(2u32), &c.g.clone());
    let got_x = match &kG {
        Point::Affine { x, .. } => hex::encode(x.to_bytes_be()),
        Point::Infinity => panic!("2*G should not be infinity"),
    };
    // Left-pad to 132 hex chars (66 bytes)
    let got_padded = format!("{:0>132}", got_x);
    assert_eq!(got_padded, K2_POINT_X_HEX,
        "2*G x-coord mismatch\n  got: {}\n  exp: {}", got_padded, K2_POINT_X_HEX);
}

// =========================================================
// TEST 5: HKDF-SHA-512 on known shared_x → AES key+nonce
// =========================================================
#[test]
fn tv_hkdf_sha512_from_shared_x() {
    let shared_x = h2b(SHARED_X_HEX);
    let out = hkdf_sha512_64(&shared_x, HKDF_SALT, HKDF_INFO);

    assert_eq!(hex::encode(&out[..32]), AES_KEY_HEX,
        "HKDF-SHA-512 first 32 bytes (AES key) mismatch");
    assert_eq!(hex::encode(&out[32..44]), AES_NONCE_HEX,
        "HKDF-SHA-512 bytes 32..44 (GCM nonce) mismatch");
}

// =========================================================
// TEST 6: Full ECDH → HKDF → AES-GCM pipeline
// =========================================================
#[test]
fn tv_full_pipeline_alice_to_ciphertext() {
    let curve = bcs521();

    let alice_sk = BigUint::from_bytes_be(&h2b(ALICE_SK_HEX));
    let bob_pk = Point::Affine {
        x: BigUint::from_bytes_be(&h2b(BOB_PK_X_HEX)),
        y: BigUint::from_bytes_be(&h2b(BOB_PK_Y_HEX)),
    };

    curve.validate_public_key(&bob_pk).expect("bob_pk invalid");
    let shared_x = curve.ecdh(&alice_sk, &bob_pk).expect("ECDH failed");
    assert_eq!(hex::encode(&shared_x), SHARED_X_HEX, "ECDH shared_x mismatch");

    let hkdf_out = hkdf_sha512_64(&shared_x, HKDF_SALT, HKDF_INFO);
    let aes_key: &Key<Aes256Gcm> = hkdf_out[..32].try_into().unwrap();
    let cipher = Aes256Gcm::new(aes_key);
    let nonce = Nonce::from_slice(&hkdf_out[32..44]);

    let ct_tag = cipher
        .encrypt(nonce, Payload { msg: AES_PLAINTEXT, aad: AES_AAD })
        .expect("AES-GCM encrypt failed");

    let mut expected = h2b(AES_CIPHERTEXT_HEX);
    expected.extend_from_slice(&h2b(AES_TAG_HEX));
    assert_eq!(hex::encode(&ct_tag), hex::encode(&expected),
        "Full pipeline ciphertext+tag mismatch");
}

