#[test]
fn tv_kahf_dst_521_matches_python() {
    let dst = kahf_domain_separator("BCS-521-Kahf-v1");
    assert_eq!(hex::encode(dst), KAHF_DST_521_HEX, "Kahf DST hex mismatch");
}

// =========================================================
// TEST 8: Kahf-bound HKDF-SHA-512 matches Python reference
// =========================================================
#[test]
fn tv_kahf_hkdf_from_shared_x() {
    let shared_x = h2b(SHARED_X_HEX);
    let out = hkdf_sha512_64_kahf(&shared_x, HKDF_SALT, HKDF_INFO);
    assert_eq!(hex::encode(out), KAHF_HKDF64_HEX,
        "Kahf-bound HKDF-SHA-512 (64 B) mismatch");
    assert_eq!(hex::encode(&out[..32]), KAHF_AES_KEY_HEX);
    assert_eq!(hex::encode(&out[32..44]), KAHF_NONCE_HEX);
}

// =========================================================
// TEST 9: Kahf-bound full pipeline ECDH → HKDF-Kahf → AES-GCM
// =========================================================
#[test]
fn tv_kahf_full_pipeline() {
    let curve = bcs521();

    let alice_sk = BigUint::from_bytes_be(&h2b(ALICE_SK_HEX));
    let bob_pk = Point::Affine {
        x: BigUint::from_bytes_be(&h2b(BOB_PK_X_HEX)),
        y: BigUint::from_bytes_be(&h2b(BOB_PK_Y_HEX)),
    };

    curve.validate_public_key(&bob_pk).expect("bob_pk invalid");
    let shared_x = curve.ecdh(&alice_sk, &bob_pk).expect("ECDH failed");

    let hkdf_out = hkdf_sha512_64_kahf(&shared_x, HKDF_SALT, HKDF_INFO);
    let aes_key: &Key<Aes256Gcm> = hkdf_out[..32].try_into().unwrap();
    let cipher = Aes256Gcm::new(aes_key);
    let nonce = Nonce::from_slice(&hkdf_out[32..44]);

    let ct_tag = cipher
        .encrypt(nonce, Payload { msg: AES_PLAINTEXT, aad: AES_AAD })
        .expect("AES-GCM encrypt failed");

    let mut expected = h2b(KAHF_CIPHERTEXT_HEX);
    expected.extend_from_slice(&h2b(KAHF_TAG_HEX));
    assert_eq!(hex::encode(&ct_tag), hex::encode(&expected),
        "Kahf-bound full pipeline ciphertext+tag mismatch");
}

// =========================================================
// TEST 10: Kahf binding actually changes ciphertext
// =========================================================
#[test]
fn tv_kahf_differs_from_plain() {
    assert_ne!(KAHF_AES_KEY_HEX, AES_KEY_HEX,
        "Kahf AES key MUST differ from plain");
    assert_ne!(KAHF_CIPHERTEXT_HEX, AES_CIPHERTEXT_HEX,
        "Kahf ciphertext MUST differ from plain");
}
